const rateLimiter = (fn, limit, interval) => {
  let requestCount = 0;
  let timeout;
  return (...args) => {
    if (requestCount < limit) {
      fn.apply(args);
      requestCount++;
    }
    if (!timeout) {
      timeout = setTimeout(() => {
        requestCount = 0;
        timeout = null;
      }, interval);
    }
  };
};

const apiCall = () => {
  console.log("api called");
};

const limitedApiCall = rateLimiter(apiCall, 4, 60 * 1000);
